library;

import 'dart:math' as math;

import 'package:flutter_test/flutter_test.dart';

import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';

void main() {
  test('CPU Mandelbrot canonical render is stable + non-blocky', () {
    const w = 128;
    const h = 128;

    const moduleId = 'mandelbrot';
    const panX = -0.5;
    const panY = 0.0;
    const zoom = 1.0;
    const baseIters = 220;
    const bailout = 4.0;
    const aa = 4;

    final extra = (math.log(math.max(zoom, 1.0)) / math.ln2 * 32.0).round();
    final iters = (baseIters + extra).clamp(50, 5000);

    final resp = renderCpuFrameInIsolate(
      CpuRenderRequest(
        moduleId: moduleId,
        panX: panX,
        panY: panY,
        zoom: zoom,
        iterations: iters,
        bailout: bailout,
        juliaCX: -0.8,
        juliaCY: 0.156,
        width: w,
        height: h,
        sampleCount: aa,
      ),
    );

    // Quick sanity checks.
    final rgba = resp.rgba;
    int nonBlack = 0;
    final lumBins = List<int>.filled(32, 0);
    double lumAt(int px, int py) {
      final idx = (py * w + px) * 4;
      final r = rgba[idx];
      final g = rgba[idx + 1];
      final b = rgba[idx + 2];
      return 0.2126 * r + 0.7152 * g + 0.0722 * b;
    }

    for (int y = 0; y < h; y++) {
      for (int x = 0; x < w; x++) {
        final idx = (y * w + x) * 4;
        if (rgba[idx] > 8 || rgba[idx + 1] > 8 || rgba[idx + 2] > 8) {
          nonBlack++;
        }
        final l = lumAt(x, y);
        final b =
            (l / 256.0 * lumBins.length).floor().clamp(0, lumBins.length - 1);
        lumBins[b]++;
      }
    }

    expect(nonBlack / (w * h), greaterThan(0.10),
        reason: 'Should not be mostly black');

    // Not gradient-only / flat: require some luminance diversity.
    final nonZeroBins = lumBins.where((c) => c > (w * h * 0.001)).length;
    expect(nonZeroBins, greaterThanOrEqualTo(6),
        reason: 'Too few luminance bins (flat/gradient-only)');

    // Blockiness metric: large flat 8x8 blocks are a regression.
    // We compute the mean per-block luminance and count identical adjacent blocks.

    const bs = 8;
    final bw = w ~/ bs;
    final bh = h ~/ bs;
    final block = List<double>.filled(bw * bh, 0);

    for (int by = 0; by < bh; by++) {
      for (int bx = 0; bx < bw; bx++) {
        double acc = 0;
        for (int y = 0; y < bs; y++) {
          for (int x = 0; x < bs; x++) {
            acc += lumAt(bx * bs + x, by * bs + y);
          }
        }
        block[by * bw + bx] = acc / (bs * bs);
      }
    }

    int sameAdj = 0;
    int adj = 0;
    for (int by = 0; by < bh; by++) {
      for (int bx = 0; bx < bw; bx++) {
        final v = block[by * bw + bx];
        if (bx + 1 < bw) {
          adj++;
          if ((v - block[by * bw + (bx + 1)]).abs() < 0.25) sameAdj++;
        }
        if (by + 1 < bh) {
          adj++;
          if ((v - block[(by + 1) * bw + bx]).abs() < 0.25) sameAdj++;
        }
      }
    }

    final ratio = sameAdj / adj;
    // Empirical: a properly rendered Mandelbrot should have lots of boundaries,
    // so adjacent blocks shouldn't all be identical.
    expect(ratio, lessThan(0.80),
        reason: 'Too many identical adjacent blocks (blocky render)');
  });
}

import 'dart:typed_data';

import 'package:vector_math/vector_math.dart' show Vector2;

import 'cpu_formulas.dart';
import 'cpu_viewport_mapping.dart';

export 'cpu_viewport_mapping.dart'
    show CpuRenderDimensions, CpuRenderRect, CpuRenderSamplePoint;

/// Message used to request a CPU frame render from an isolate.
final class CpuRenderRequest {
  const CpuRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.width,
    required this.height,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;
  final int width;
  final int height;
  final int sampleCount;
}

final class CpuRenderResponse {
  const CpuRenderResponse({
    required this.rgba,
    required this.width,
    required this.height,
  });

  /// RGBA8888 bytes.
  final Uint8List rgba;
  final int width;
  final int height;
}

/// Top-level entrypoint suitable for [Isolate.run].
CpuRenderResponse renderCpuFrameInIsolate(CpuRenderRequest req) {
  final bytes = renderCpuRectRgba(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    // Full viewport
    fullWidth: req.width,
    fullHeight: req.height,
    // Tile == full
    x0: 0,
    y0: 0,
    w: req.width,
    h: req.height,
    sampleCount: req.sampleCount,
  );
  return CpuRenderResponse(rgba: bytes, width: req.width, height: req.height);
}

final class CpuTileRenderRequest {
  const CpuTileRenderRequest({
    required this.moduleId,
    required this.panX,
    required this.panY,
    required this.zoom,
    required this.iterations,
    required this.bailout,
    required this.juliaCX,
    required this.juliaCY,
    required this.fullWidth,
    required this.fullHeight,
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.sampleCount,
  });

  final String moduleId;
  final double panX;
  final double panY;
  final double zoom;
  final int iterations;
  final double bailout;
  final double juliaCX;
  final double juliaCY;

  final int fullWidth;
  final int fullHeight;
  final int x0;
  final int y0;
  final int w;
  final int h;
  final int sampleCount;
}

final class CpuTileRenderResponse {
  const CpuTileRenderResponse({
    required this.x0,
    required this.y0,
    required this.w,
    required this.h,
    required this.rgba,
  });

  final int x0;
  final int y0;
  final int w;
  final int h;
  final Uint8List rgba;
}

final class CpuViewportCoordinate {
  const CpuViewportCoordinate(this.x, this.y);

  final double x;
  final double y;
}

/// Maps a pixel sample to the CPU fractal plane.
///
/// [sampleOffsetX] and [sampleOffsetY] are normalized offsets within the pixel
/// (0.5 means pixel center). Dividing by the full dimensions keeps one-pixel
/// renders centered on pan and keeps opposite edge pixel centers symmetric.
CpuViewportCoordinate cpuViewportCoordinateForSample({
  required double panX,
  required double panY,
  required double zoom,
  required int fullWidth,
  required int fullHeight,
  required int x,
  required int y,
  required double sampleOffsetX,
  required double sampleOffsetY,
}) {
  CpuRenderSamplePoint(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x: x,
    y: y,
  ).validate();

  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );
  final nx = viewport.normalizedSampleOffset(
    pixel: x,
    extent: fullWidth,
    sampleOffset: sampleOffsetX,
  );
  final ny = viewport.normalizedSampleOffset(
    pixel: y,
    extent: fullHeight,
    sampleOffset: sampleOffsetY,
  );
  final coordinate = viewport.coordinate(nx: nx, ny: ny);

  return CpuViewportCoordinate(coordinate.$1, coordinate.$2);
}

CpuTileRenderResponse renderCpuTileInIsolate(CpuTileRenderRequest req) {
  final bytes = renderCpuRectRgba(
    moduleId: req.moduleId,
    panX: req.panX,
    panY: req.panY,
    zoom: req.zoom,
    iterations: req.iterations,
    bailout: req.bailout,
    juliaCX: req.juliaCX,
    juliaCY: req.juliaCY,
    fullWidth: req.fullWidth,
    fullHeight: req.fullHeight,
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    sampleCount: req.sampleCount,
  );

  return CpuTileRenderResponse(
    x0: req.x0,
    y0: req.y0,
    w: req.w,
    h: req.h,
    rgba: bytes,
  );
}

/// Renders one CPU RGBA tile from an explicit full-viewport rectangle.
///
/// This pure raster helper is shared by direct, full-frame isolate, and tile
/// isolate render paths so they fail on the same invalid dimensions and sample
/// the same viewport coordinates.
Uint8List renderCpuRectRgba({
  required String moduleId,
  required double panX,
  required double panY,
  required double zoom,
  required int iterations,
  required double bailout,
  required double juliaCX,
  required double juliaCY,
  required int fullWidth,
  required int fullHeight,
  required int x0,
  required int y0,
  required int w,
  required int h,
  required int sampleCount,
}) {
  CpuRenderRect(
    fullWidth: fullWidth,
    fullHeight: fullHeight,
    x0: x0,
    y0: y0,
    w: w,
    h: h,
  ).validate();

  final bytes = Uint8List(w * h * 4);
  final sampleGrid = CpuSampleGrid.fromRequestedCount(sampleCount);

  final juliaC = Vector2(juliaCX, juliaCY);
  final formula = cpuFormulaForModuleId(moduleId);
  final viewport = CpuViewportMapping.fromScalars(
    panX: panX,
    panY: panY,
    viewZoom: zoom,
    width: fullWidth,
    height: fullHeight,
  );

  for (int ty = 0; ty < h; ty++) {
    final y = y0 + ty;
    for (int tx = 0; tx < w; tx++) {
      final x = x0 + tx;

      double rAcc = 0;
      double gAcc = 0;
      double bAcc = 0;

      for (int sy = 0; sy < sampleGrid.samplesPerAxis; sy++) {
        for (int sx = 0; sx < sampleGrid.samplesPerAxis; sx++) {
          final nx = viewport.normalizedSample(
            pixel: x,
            extent: fullWidth,
            sample: sx,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final ny = viewport.normalizedSample(
            pixel: y,
            extent: fullHeight,
            sample: sy,
            samplesPerAxis: sampleGrid.samplesPerAxis,
          );
          final coordinate = viewport.coordinate(nx: nx, ny: ny);

          final color = formula(
            coordinate.$1,
            coordinate.$2,
            iterations,
            bailout,
            juliaC,
          );
          rAcc += color.$1;
          gAcc += color.$2;
          bAcc += color.$3;
        }
      }

      final idx = (ty * w + tx) * 4;
      bytes[idx + 0] = (rAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 1] = (gAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 2] = (bAcc / sampleGrid.totalSamples).clamp(0, 255).round();
      bytes[idx + 3] = 255;
    }
  }

  return bytes;
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/builders/escape_time/catalog.dart';
import 'package:flutter_fractals/core/modules/builders/raymarched_3d/catalog.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/features/catalog/catalog_entry.dart';

/// Catalog data source for the Explore screen.
///
/// Phase 1: derives entries from currently implemented modules while assigning
/// stable catalog IDs. This keeps IDs future-proof for PRD-200 ingest.
class CatalogRepository {
  final List<CatalogEntry> entries;

  const CatalogRepository({required this.entries});

  factory CatalogRepository.fromRegistry(ModuleRegistry registry) {
    final categoriesById = {
      for (final config in escapeTimeCatalog) config.id: config.category,
      for (final config in raymarched3DCatalog) config.id: config.category,
    };

    return CatalogRepository(
      entries: registry.modules
          .map(
            (module) => CatalogEntry(
              // Stable prefix to decouple future module refactors from IDs.
              catalogId: 'core.${module.id}',
              module: module,
              category: categoriesById[module.id] ??
                  (module.dimension == FractalDimension.threeD
                      ? '3D Fractals'
                      : 'Other'),
            ),
          )
          .toList(growable: false),
    );
  }

  CatalogEntry byCatalogId(String catalogId) {
    return entries.firstWhere((entry) => entry.catalogId == catalogId);
  }

  @visibleForTesting
  Set<String> allIds() => entries.map((e) => e.catalogId).toSet();
}

import 'package:flutter/foundation.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';

/// Stable catalog entry used by the redesigned browser.
///
/// This is intentionally separate from [FractalModule] so we can scale the
/// catalog to many entries (e.g. PRD 200) while still mapping to currently
/// implemented render modules.
@immutable
class CatalogEntry {
  /// Stable ID for catalog persistence, analytics, and deep links.
  ///
  /// Must never change once published.
  final String catalogId;

  /// Backing runtime fractal module that can render this entry today.
  final FractalModule module;

  /// Display category used to group entries in the catalog UI.
  final String category;

  /// Optional search aliases used by catalog filtering.
  final List<String> aliases;

  const CatalogEntry({
    required this.catalogId,
    required this.module,
    required this.category,
    this.aliases = const [],
  });
}

import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/modules/fractal_module.dart';
import 'package:flutter_fractals/features/catalog/catalog_repository.dart';
import 'package:flutter_test/flutter_test.dart';

void main() {
  group('CatalogRepository', () {
    test('creates stable prefixed IDs from module registry', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.entries, isNotEmpty);
      expect(repo.entries.length, registry.modules.length);
      expect(repo.entries.first.catalogId, startsWith('core.'));
      expect(repo.byCatalogId('core.mandelbrot').module.id, 'mandelbrot');
    });

    test('catalog IDs are unique', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(repo.allIds().length, repo.entries.length);
    });

    test('keeps intended 3D runtime modules for implemented 3D catalog ids', () {
      final registry = ModuleRegistry();
      final repo = CatalogRepository.fromRegistry(registry);

      expect(
        repo.byCatalogId('core.quaternion_julia_3d').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.dual_quaternion_julia').module.dimension,
        FractalDimension.threeD,
      );
      expect(
        repo.byCatalogId('core.mandelbox_shape_inversion').module.dimension,
        FractalDimension.threeD,
      );
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/modules/module_registry.dart';
import 'package:flutter_fractals/core/theme/app_theme.dart';
import 'package:flutter_fractals/features/catalog/fractal_catalog_screen.dart';
import 'package:flutter_fractals/features/renderer/providers/fractal_provider.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:provider/provider.dart';
import 'package:shared_preferences/shared_preferences.dart';

void main() {
  setUp(() {
    TestWidgetsFlutterBinding.ensureInitialized();
    SharedPreferences.setMockInitialValues({});
  });

  Future<void> pumpCatalog(WidgetTester tester) async {
    final registry = ModuleRegistry();

    await tester.pumpWidget(
      MultiProvider(
        providers: [
          Provider<ModuleRegistry>.value(value: registry),
          ChangeNotifierProvider<FractalController>(
            create: (_) => FractalController(registry),
          ),
        ],
        child: const MaterialApp(
          locale: Locale('en'),
          localizationsDelegates: AppLocalizations.localizationsDelegates,
          supportedLocales: AppLocalizations.supportedLocales,
          home: Scaffold(
            body: FractalCatalogScreen(),
          ),
        ),
      ),
    );

    // Bounded pumps instead of pumpAndSettle: catalog shimmer animations repeat.
    await tester.pump();
    await tester.pump(const Duration(milliseconds: 100));
  }

  Future<void> showSearch(WidgetTester tester) async {
    await tester.tap(find.byIcon(Icons.search_rounded));
    await tester.pump();
    await tester.pump();

    expect(find.byKey(const Key('catalogSearchField')), findsOneWidget);
  }

  int allDimensionCount(WidgetTester tester) {
    final countTexts = tester
        .widgetList<Text>(
          find.descendant(
            of: find.byKey(const Key('catalogDimensionChip_all')),
            matching: find.byType(Text),
          ),
        )
        .map((text) => text.data)
        .whereType<String>()
        .toList();
    return int.parse(countTexts.last);
  }

  testWidgets('Catalog search filters fractal modules', (tester) async {
    await pumpCatalog(tester);
    final initialCount = allDimensionCount(tester);
    await showSearch(tester);

    await tester.enterText(
      find.byKey(const Key('catalogSearchField')),
      'Julia',
    );
    await tester.pump(const Duration(milliseconds: 300));

    expect(find.text('Julia'), findsWidgets);
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search field uses the focused visual state',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final searchField = tester.widget<TextField>(
      find.byKey(const Key('catalogSearchField')),
    );
    expect(searchField.focusNode?.hasFocus, isTrue);

    final container = tester.widget<AnimatedContainer>(
      find.byKey(const Key('catalogSearchContainer')),
    );
    final decoration = container.decoration! as BoxDecoration;
    final border = decoration.border! as Border;

    expect(border.top.color, AppColors.primary.withValues(alpha: 0.6));
    expect(border.top.width, 1.5);

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search debounce waits for the latest edit',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final initialCount = allDimensionCount(tester);
    final searchField = find.byKey(const Key('catalogSearchField'));
    await tester.enterText(searchField, 'J');
    await tester.pump(const Duration(milliseconds: 150));
    await tester.enterText(searchField, 'Julia');

    // More than 300ms after the first edit, but less than 300ms after the
    // latest edit. Search results should still show the unfiltered catalog.
    await tester.pump(const Duration(milliseconds: 200));
    expect(allDimensionCount(tester), initialCount);

    await tester.pump(const Duration(milliseconds: 100));
    expect(find.text('Julia'), findsWidgets);
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.pump(const Duration(seconds: 3));
  });

  testWidgets('Catalog search clear icon resets the applied query immediately',
      (tester) async {
    await pumpCatalog(tester);
    await showSearch(tester);

    final initialCount = allDimensionCount(tester);
    final searchField = find.byKey(const Key('catalogSearchField'));

    await tester.enterText(searchField, 'Julia');
    await tester.pump(const Duration(milliseconds: 300));
    expect(allDimensionCount(tester), lessThan(initialCount));

    await tester.tap(find.byKey(const ValueKey('clear')));
    await tester.pump();

    expect(allDimensionCount(tester), initialCount);

    await tester.pump(const Duration(seconds: 3));
  });
}

import 'dart:math';

import 'package:flutter_fractals/features/renderer/deep_zoom_precision_policy.dart';

/// Auto-zoom configuration.
class AutoExploreConfig {
  static const double defaultMinZoom = 0.2;
  static const double defaultMaxZoom = 1e12;

  /// Minimum and maximum zoom targets for the auto cycle.
  final double minZoom;
  final double maxZoom;

  /// Peak zoom target starts from: baseZoom * [cycleMaxMultiplier], then gets
  /// clamped by smart precision limits per fractal module.
  final double cycleMaxMultiplier;

  /// Maximum zoom span per leg in log10 decades (e.g. 3.0 => up to 1000x).
  final double maxLegSpanDecades;

  /// Precision headroom under policy threshold to avoid probing unstable edges.
  final double precisionHeadroom;

  /// Duration for each zoom leg (in or out).
  final Duration travelDuration;

  /// Maximum multiplier for duration scaling on very large zoom spans.
  final double maxDurationScale;

  const AutoExploreConfig({
    this.minZoom = defaultMinZoom,
    this.maxZoom = defaultMaxZoom,
    this.cycleMaxMultiplier = 120.0,
    this.maxLegSpanDecades = 3.2,
    this.precisionHeadroom = 0.92,
    this.travelDuration = const Duration(milliseconds: 9000),
    this.maxDurationScale = 4.0,
  });
}

/// Speed bounds used by auto-explore playback.
///
/// Dart's [double.clamp] treats NaN as the upper bound. For playback speed,
/// invalid telemetry or UI state should fall back to neutral 1.0x instead of
/// silently selecting the fastest supported speed.
class AutoExploreSpeed {
  static const double min = 0.5;
  static const double neutral = 1.0;
  static const double max = 3.0;

  const AutoExploreSpeed._();

  static const int sliderDivisions = 25;

  static double normalize(double speed) {
    if (!speed.isFinite) return neutral;
    return speed.clamp(min, max);
  }
}

/// Relative epsilon used to ignore tiny user zoom corrections.
///
/// Values at or above 1.0 invert the lower comparison bound and make zoom-out
/// corrections undetectable. Keep normalization explicit so correction replay
/// tests can distinguish real deadbands from malformed inputs.
class AutoExploreRelativeEpsilon {
  static const double defaultValue = 1e-4;

  const AutoExploreRelativeEpsilon._();

  static double normalize(double epsilon) {
    if (!epsilon.isFinite || epsilon < 0.0 || epsilon >= 1.0) {
      return defaultValue;
    }
    return epsilon;
  }
}

/// Direction inferred from a user zoom correction.
class AutoExploreCorrectionDecision {
  static const double defaultRelativeEpsilon =
      AutoExploreRelativeEpsilon.defaultValue;

  /// Null means the correction is inside the deadband and should preserve the
  /// current auto-explore direction.
  final bool? zoomingInOverride;

  const AutoExploreCorrectionDecision._(this.zoomingInOverride);

  bool get changedDirection => zoomingInOverride != null;

  bool resolve({required bool currentZoomingIn}) =>
      zoomingInOverride ?? currentZoomingIn;

  factory AutoExploreCorrectionDecision.fromZooms({
    required double currentZoom,
    required double previousZoom,
    double relativeEpsilon = defaultRelativeEpsilon,
  }) {
    if (!_isUsableZoomSample(currentZoom) ||
        !_isUsableZoomSample(previousZoom)) {
      return const AutoExploreCorrectionDecision._(null);
    }

    final epsilon = AutoExploreRelativeEpsilon.normalize(relativeEpsilon);
    if (currentZoom > previousZoom * (1.0 + epsilon)) {
      return const AutoExploreCorrectionDecision._(true);
    }
    if (currentZoom < previousZoom * (1.0 - epsilon)) {
      return const AutoExploreCorrectionDecision._(false);
    }
    return const AutoExploreCorrectionDecision._(null);
  }

  static bool _isUsableZoomSample(double zoom) => zoom.isFinite && zoom > 0.0;
}

/// Replayable result of adopting a user-selected zoom into auto-explore.
///
/// The service stores several state fields while timers are active. Keeping the
/// zoom comparison and direction decision pure makes the hidden fallback order
/// testable: prefer the interaction-start zoom, otherwise the last correction
/// sample, otherwise the current zoom.
class AutoExploreZoomAdoption {
  final double currentZoom;
  final double previousZoom;
  final bool zoomingIn;
  final AutoExploreCorrectionDecision correctionDecision;

  const AutoExploreZoomAdoption({
    required this.currentZoom,
    required this.previousZoom,
    required this.zoomingIn,
    required this.correctionDecision,
  });

  factory AutoExploreZoomAdoption.fromSamples({
    required AutoExploreZoomBounds bounds,
    required double currentZoom,
    required double? referenceZoom,
    required double? lastCorrectionZoom,
    required bool wasZoomingIn,
  }) {
    final current = bounds.clamp(currentZoom);
    final previous = bounds.clamp(
      referenceZoom ?? lastCorrectionZoom ?? current,
    );
    final decision = AutoExploreCorrectionDecision.fromZooms(
      currentZoom: current,
      previousZoom: previous,
    );

    return AutoExploreZoomAdoption(
      currentZoom: current,
      previousZoom: previous,
      zoomingIn: decision.resolve(currentZoomingIn: wasZoomingIn),
      correctionDecision: decision,
    );
  }
}

/// Precision headroom used to keep auto-explore below renderer fallback edges.
///
/// Values above 1.0 would push candidates past the module precision threshold;
/// non-finite values must not rely on [double.clamp] because NaN clamps to the
/// upper bound and would silently promote targets to max zoom.
class AutoExplorePrecisionHeadroom {
  static const double neutral = 1.0;

  const AutoExplorePrecisionHeadroom._();

  static double normalize(double headroom) {
    if (!headroom.isFinite || headroom <= 0.0) return neutral;
    return headroom.clamp(0.0, neutral);
  }
}

/// Cycle shape used by auto-explore target planning.
///
/// Invalid multipliers or span limits can otherwise turn zoom-out floors into
/// max zooms or collapse peak candidates into NaN/minimum zooms. Keeping the
/// cycle shape explicit makes candidate planning replayable from config alone.
class AutoExploreCycleShape {
  final double cycleMaxMultiplier;
  final double maxLegSpanDecades;

  const AutoExploreCycleShape({
    required this.cycleMaxMultiplier,
    required this.maxLegSpanDecades,
  });

  factory AutoExploreCycleShape.fromConfig(AutoExploreConfig config) {
    return AutoExploreCycleShape(
      cycleMaxMultiplier: _finiteAtLeastNeutralOrDefault(
        config.cycleMaxMultiplier,
        const AutoExploreConfig().cycleMaxMultiplier,
      ),
      maxLegSpanDecades: _finiteNonNegativeOrDefault(
        config.maxLegSpanDecades,
        const AutoExploreConfig().maxLegSpanDecades,
      ),
    );
  }

  double get maxLegSpanRatio => pow(10.0, maxLegSpanDecades).toDouble();

  static double _finiteAtLeastNeutralOrDefault(double value, double fallback) {
    return value.isFinite && value >= 1.0 ? value : fallback;
  }

  static double _finiteNonNegativeOrDefault(double value, double fallback) {
    return value.isFinite && value >= 0.0 ? value : fallback;
  }
}

/// Duration scaling used by auto-explore zoom legs.
///
/// Invalid scale factors can otherwise flow into [double.round], where NaN or
/// infinity throws instead of producing a replayable fallback duration.
